const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

// Find pending posts that are due
const now = new Date().toISOString();
const posts = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/scheduled_posts?status=eq.pending&scheduled_at=lte.' + now + '&order=scheduled_at.asc&limit=5',
  headers: pgHeaders
});

if (!posts || posts.length === 0) {
  return [{ json: { published: 0 } }];
}

// Load Instagram credentials
const creds = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/template_credentials?template_id=eq.instagram-post&select=cred_key,cred_value',
  headers: pgHeaders
});
const credMap = {};
for (const c of (creds || [])) credMap[c.cred_key] = c.cred_value;

let published = 0;

for (const post of posts) {
  if (post.platform !== 'instagram') {
    // Mark unsupported platforms as failed
    await helpers.httpRequest({
      method: 'PATCH',
      url: baseUrl + '/rest/v1/scheduled_posts?id=eq.' + post.id,
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'failed', error_message: 'Platform nicht unterstützt: ' + post.platform })
    });
    continue;
  }

  const token = credMap.instagram_token;
  const userId = credMap.instagram_user_id;

  if (!token || !userId) {
    await helpers.httpRequest({
      method: 'PATCH',
      url: baseUrl + '/rest/v1/scheduled_posts?id=eq.' + post.id,
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'failed', error_message: 'Instagram-Credentials fehlen' })
    });
    continue;
  }

  try {
    // Create container
    const containerBody = { caption: post.caption, access_token: token };
    if (post.image_url) containerBody.image_url = post.image_url;

    const container = await helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v21.0/' + userId + '/media',
      body: containerBody
    });

    if (!container.id) throw new Error('Container-Erstellung fehlgeschlagen');

    // Wait for ready
    let ready = false;
    for (let i = 0; i < 10; i++) {
      const status = await helpers.httpRequest({
        method: 'GET',
        url: 'https://graph.facebook.com/v21.0/' + container.id + '?fields=status_code&access_token=' + token
      });
      if (status.status_code === 'FINISHED') { ready = true; break; }
      if (status.status_code === 'ERROR') throw new Error('Container Error');
      await new Promise(r => setTimeout(r, 2000));
    }
    if (!ready) throw new Error('Container timeout');

    // Publish
    const pub = await helpers.httpRequest({
      method: 'POST',
      url: 'https://graph.facebook.com/v21.0/' + userId + '/media_publish',
      body: { creation_id: container.id, access_token: token }
    });

    // Mark as published
    await helpers.httpRequest({
      method: 'PATCH',
      url: baseUrl + '/rest/v1/scheduled_posts?id=eq.' + post.id,
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'published', published_post_id: pub.id })
    });
    published++;
  } catch(e) {
    await helpers.httpRequest({
      method: 'PATCH',
      url: baseUrl + '/rest/v1/scheduled_posts?id=eq.' + post.id,
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'failed', error_message: e.message })
    });
  }
}

return [{ json: { published, total_pending: posts.length } }];
